// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract EnglishAuction {
    address public seller;
    uint256 public auctionEnd;
    address public highestBidder;
    uint256 public highestBid;
    bool public withdrawn;

    error AuctionEnded();
    error BidTooLow();
    error AuctionStillActive();
    error AlreadyWithdrawn();
    error OnlySeller();

    constructor(address _seller, uint256 _duration) {
        seller = _seller;
        auctionEnd = block.timestamp + _duration;
    }

    function bid() external payable {
        if ([[SLOT ended_check]]) revert AuctionEnded();
        if ([[SLOT low_bid]]) revert BidTooLow();

        address previousBidder = highestBidder;
        uint256 previousBid = highestBid;

        highestBidder = msg.sender;
        highestBid = msg.value;

        if (previousBidder != address(0)) {
            [[SLOT refund_prev]]
        }
    }

    function withdraw() external {
        if (msg.sender != seller) revert OnlySeller();
        if (block.timestamp < auctionEnd) revert AuctionStillActive();
        if (withdrawn) revert AlreadyWithdrawn();

        withdrawn = true;
        [[SLOT settle]]
    }

    function getHighestBid() external view returns (address bidder, uint256 amount) {
        return (highestBidder, highestBid);
    }
}
